"""sklearn.impute — Missing value imputation."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


class SimpleImputer(BaseEstimator, TransformerMixin):
    """Impute missing values with a simple strategy.

    Parameters
    ----------
    missing_values : float, default=np.nan
    strategy : str, default='mean'
        One of 'mean', 'median', 'most_frequent', 'constant'.
    fill_value : any, default=None
    """

    def __init__(self, *, missing_values=np.nan, strategy='mean',
                 fill_value=None, copy=True, add_indicator=False,
                 keep_empty_features=False):
        self.missing_values = missing_values
        self.strategy = strategy
        self.fill_value = fill_value
        self.copy = copy
        self.add_indicator = add_indicator
        self.keep_empty_features = keep_empty_features

    def _is_missing(self, X):
        if np.isnan(self.missing_values):
            return np.isnan(X)
        return X == self.missing_values

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        n_features = X.shape[1]
        self.statistics_ = np.zeros(n_features)
        for j in range(n_features):
            col = X[:, j]
            mask = ~self._is_missing(col.reshape(-1, 1)).ravel()
            valid = col[mask]
            if self.strategy == 'mean':
                self.statistics_[j] = np.mean(valid) if len(valid) > 0 else 0
            elif self.strategy == 'median':
                self.statistics_[j] = np.median(valid) if len(valid) > 0 else 0
            elif self.strategy == 'most_frequent':
                if len(valid) > 0:
                    vals, counts = np.unique(valid, return_counts=True)
                    self.statistics_[j] = vals[np.argmax(counts)]
            elif self.strategy == 'constant':
                self.statistics_[j] = self.fill_value if self.fill_value is not None else 0
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float).copy()
        for j in range(X.shape[1]):
            missing = self._is_missing(X[:, j:j+1]).ravel()
            X[missing, j] = self.statistics_[j]
        return X


class KNNImputer(BaseEstimator, TransformerMixin):
    """Impute missing values using k-nearest neighbours.

    Parameters
    ----------
    n_neighbors : int, default=5
    weights : str, default='uniform'
    """

    def __init__(self, *, missing_values=np.nan, n_neighbors=5,
                 weights='uniform', metric='nan_euclidean', copy=True,
                 add_indicator=False, keep_empty_features=False):
        self.missing_values = missing_values
        self.n_neighbors = n_neighbors
        self.weights = weights
        self.metric = metric
        self.copy = copy
        self.add_indicator = add_indicator
        self.keep_empty_features = keep_empty_features

    def fit(self, X, y=None):
        self.fit_X_ = np.asarray(X, dtype=float).copy()
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float).copy()
        for i in range(X.shape[0]):
            missing_cols = np.where(np.isnan(X[i]))[0]
            if len(missing_cols) == 0:
                continue
            obs_cols = np.where(~np.isnan(X[i]))[0]
            if len(obs_cols) == 0:
                X[i, missing_cols] = np.nanmean(self.fit_X_[:, missing_cols], axis=0)
                continue
            # Distance on observed features
            diffs = self.fit_X_[:, obs_cols] - X[i, obs_cols]
            # Handle NaN in training data
            diffs = np.nan_to_num(diffs, nan=0)
            dists = np.sqrt(np.sum(diffs ** 2, axis=1))
            k = min(self.n_neighbors, len(dists))
            nn_idx = np.argsort(dists)[:k]
            for j in missing_cols:
                nn_vals = self.fit_X_[nn_idx, j]
                valid = ~np.isnan(nn_vals)
                if valid.any():
                    if self.weights == 'distance':
                        w = 1.0 / (dists[nn_idx][valid] + 1e-15)
                        X[i, j] = np.average(nn_vals[valid], weights=w)
                    else:
                        X[i, j] = np.mean(nn_vals[valid])
                else:
                    X[i, j] = np.nanmean(self.fit_X_[:, j])
        return X
